from pandera.typing import DataFrame, Series
import pandera as pa

class OrderSchema(pa.DataFrameModel):
    order_id: Series[str] = pa.Field(str_startswith="ORD-")
    amount: Series[float] = pa.Field(gt=0)
    status: Series[str] = pa.Field(isin=["pending", "shipped", "delivered"])

    class Config:
        coerce = True

@pa.check_types
def transform_orders(df: DataFrame[OrderSchema]) -> DataFrame[OrderSchema]:
    df["amount_with_tax"] = df["amount"] * 1.1
    return df

