def split_valid_invalid(df, schema):
    valid_mask = []
    errors = []
    for i, row in df.iterrows():
        try:
            schema.validate(row.to_frame().T)
            valid_mask.append(True)
        except Exception as e:
            valid_mask.append(False)
            errors.append({"index": i, "error": str(e), "data": row.to_dict()})
    return df[valid_mask], pd.DataFrame(errors)

