import pandas as pd
import numpy as np

class StatisticalValidator:
    def __init__(self, baseline_stats: dict):
        """
        baseline_stats: pre-computed stats from a known-good reference dataset
        e.g. {"amount": {"mean": 52.3, "std": 18.7, "null_rate": 0.01}}
        """
        self.baseline = baseline_stats

    def validate(self, df: pd.DataFrame, z_threshold: float = 3.0) -> list[str]:
        violations = []
        for col, stats in self.baseline.items():
            if col not in df.columns:
                continue

            current_mean = df[col].mean()
            baseline_mean = stats["mean"]
            baseline_std = stats["std"]

            if baseline_std == 0:
                continue

            z_score = abs(current_mean - baseline_mean) / baseline_std
            if z_score > z_threshold:
                violations.append(
                    f"{col}: mean {current_mean:.2f} deviates {z_score:.1f} std "
                    f"from baseline {baseline_mean:.2f} (threshold: {z_threshold})"
                )

            current_null_rate = df[col].isna().mean()
            allowed_null_drift = 0.05  # 5 percentage point tolerance
            if abs(current_null_rate - stats["null_rate"]) > allowed_null_drift:
                violations.append(
                    f"{col}: null rate {current_null_rate:.2%} drifted from "
                    f"baseline {stats['null_rate']:.2%}"
                )

        return violations

